var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"다른 세계에서 온 이방인을 선뜻 받아들인 건 둘째 치고, 앞으로도 잘 부탁한다니.","JPN":"別の世界からきた異邦人をあっさりと受け入れたのはともかく、これからよろしくだなんて。","ENG":"It's one thing to accept an outsider from another world so easily, but you also look forward to working with me?","TWN":"It's one thing to accept an outsider from another world so easily, but you also look forward to working with me?"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"이상한 사람이네요. 당신은 저를 의심하지는 않는 건가요?","JPN":"変な人ですね。貴方は私を疑っていないのですか？","ENG":"You're a strange one. Don't you have any suspicions about me?","TWN":"You're a strange one. Don't you have any suspicions about me?"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"이런 상황에서 호위 한 명 없다면 당신을 제압하는 건 간단합니다.","JPN":"こんな状況で護衛が1人もいないのでしたら、簡単に貴方を制圧できます。","ENG":"In a situation like this when there is no one to guard you, overpowering you would be a simple task.","TWN":"In a situation like this when there is no one to guard you, overpowering you would be a simple task."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"리더라면 좀 더 냉철한 판단을 내려주시길.","JPN":"リーダーならもっと冷徹に判断してください。","ENG":"I would expect you to make more rational decisions as a leader.","TWN":"I would expect you to make more rational decisions as a leader."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"..."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"믿는다는 말을 들을 정도의 관계는 아니라고 생각합니다.","JPN":"信頼しているという言葉を聞くほどの関係ではないと思います。","ENG":"I believe we haven't built enough trust for you to say you believe in me.","TWN":"I believe we haven't built enough trust for you to say you believe in me."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"하지만 그런 오지랖은, 나쁘지 않네요. 흔들림 없는 눈동자도 제 지인과 비슷한 느낌이에요.","JPN":"ですがそのお節介、悪くはないですね。揺るぎない瞳も私の知り合いと似ています。","ENG":"But that kind of nosiness isn't bad. That unwavering look of yours reminds me of someone I know.","TWN":"But that kind of nosiness isn't bad. That unwavering look of yours reminds me of someone I know."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"좋습니다. 적어도 당신은, 존경할만한 휴먼이니까.","JPN":"いいでしょう。少なくとも貴方は、尊敬に値するヒューマンですから。","ENG":"All right. At least you're a Human worthy of respect.","TWN":"All right. At least you're a Human worthy of respect."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"조금 이야기가 새어버렸지만… 그동안의 은혜에 보답하죠.","JPN":"少し話がそれてしまいましたが……今までの恩に報いるとしましょう。","ENG":"Our little talk might have gotten a little sidetracked, but... I will repay you for your kindness.","TWN":"Our little talk might have gotten a little sidetracked, but... I will repay you for your kindness."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"지금의 선택이 틀리지 않았다는 걸 제가 입증해 보이겠습니다.","JPN":"今この選択が間違っていなかったということを、私が証明してみせます。","ENG":"I'll prove to you that your choice wasn't wrong.","TWN":"I'll prove to you that your choice wasn't wrong."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RYU_DANMACHI_NULL_NULL","text":{"KOREA":"이 만남이, 결코 틀리지 않았다는 것도.","JPN":"この出会いが、決して間違っていなかったということも。","ENG":"And that this encounter is also not a mistake.","TWN":"And that this encounter is also not a mistake."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYU_DANMACHI_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};